static inline uint8_t marmot_bc_read_u8(const uint8_t **pc) {
    uint8_t value = 0;
    memcpy(&value, *pc, sizeof(value));
    *pc += sizeof(value);
    return value;
}

static inline uint16_t marmot_bc_read_u16(const uint8_t **pc) {
    uint16_t value = 0;
    memcpy(&value, *pc, sizeof(value));
    *pc += sizeof(value);
    return value;
}

static inline uint32_t marmot_bc_read_u32(const uint8_t **pc) {
    uint32_t value = 0;
    memcpy(&value, *pc, sizeof(value));
    *pc += sizeof(value);
    return value;
}

static inline uint64_t marmot_bc_read_u64(const uint8_t **pc) {
    uint64_t value = 0;
    memcpy(&value, *pc, sizeof(value));
    *pc += sizeof(value);
    return value;
}

static inline float marmot_bc_read_f32(const uint8_t **pc) {
    float value = 0.0f;
    memcpy(&value, *pc, sizeof(value));
    *pc += sizeof(value);
    return value;
}

static inline marmot_tensor_t *marmot_bc_reg(marmot_tensor_t **regs, uint16_t idx) {
    if (idx == MARMOT_BC_REG_INVALID) {
        return nullptr;
    }
    return regs[idx];
}

static inline const void *marmot_bc_const_data(const uint8_t *const_pool, uint32_t offset, const char *label) {
    if (offset == MARMOT_BC_INVALID_OFFSET) {
        return nullptr;
    }
    if (const_pool == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, label);
        return nullptr;
    }
    return const_pool + offset;
}

static inline const void *marmot_bc_const_ptr(const uint8_t *const_pool, uint32_t offset, const char *label) {
    if (offset == MARMOT_BC_INVALID_OFFSET) {
        return nullptr;
    }
    if (const_pool == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, label);
        return nullptr;
    }
    const void *ptr = nullptr;
    memcpy(&ptr, const_pool + offset, sizeof(ptr));
    return ptr;
}

static inline void *marmot_bc_const_ptr_mut(const uint8_t *const_pool, uint32_t offset, const char *label) {
    if (offset == MARMOT_BC_INVALID_OFFSET) {
        return nullptr;
    }
    if (const_pool == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, label);
        return nullptr;
    }
    void *ptr = nullptr;
    memcpy(&ptr, const_pool + offset, sizeof(ptr));
    return ptr;
}

#if MARMOT_ENABLE_ACCELERATE
static marmot_error_t marmot_cpu_bc_exec_abs_bf16_accelerate(
    const void *backend_exec_ctx, marmot_tensor_t **regs, const uint8_t *imm, const uint8_t *const_pool
) {
    const marmot_bc_exec_ctx_t *exec_ctx = (const marmot_bc_exec_ctx_t *)backend_exec_ctx;
    if (exec_ctx == nullptr || exec_ctx->ctx == nullptr || exec_ctx->device_ctx == nullptr || regs == nullptr ||
        imm == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Null bytecode exec arguments");
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    const marmot_context_t *ctx = exec_ctx->ctx;
    const void *device_ctx = exec_ctx->device_ctx;
    marmot_tensor_t **concat_inputs = nullptr;
    const uint8_t *pc = imm;
    uint16_t input_idx = marmot_bc_read_u16(&pc);
    uint16_t output_idx = marmot_bc_read_u16(&pc);
    uint32_t params_offset = marmot_bc_read_u32(&pc);
    const marmot_activation_params_t *params = (const marmot_activation_params_t *)marmot_bc_const_data(
        const_pool, params_offset, "Null const pool for unary params"
    );
    if (params_offset != MARMOT_BC_INVALID_OFFSET && params == nullptr) {
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    marmot_kernel_args_unary_t args = {
        .ctx = ctx,
        .input = marmot_bc_reg(regs, input_idx),
        .params = params,
        .output = marmot_bc_reg(regs, output_idx),
    };
    marmot_error_t status = marmot_cpu_abs_bf16_accelerate_exec(device_ctx, &args);
    if (concat_inputs != nullptr) {
        free(concat_inputs);
    }
    return status;
}
#endif

