static marmot_error_t marmot_cpu_bc_exec_embedding_float(
    const void *backend_exec_ctx, marmot_tensor_t **regs, const uint8_t *imm, const uint8_t *const_pool
) {
    const marmot_bc_exec_ctx_t *exec_ctx = (const marmot_bc_exec_ctx_t *)backend_exec_ctx;
    if (exec_ctx == nullptr || exec_ctx->ctx == nullptr || exec_ctx->device_ctx == nullptr || regs == nullptr ||
        imm == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Null bytecode exec arguments");
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    const marmot_context_t *ctx = exec_ctx->ctx;
    const void *device_ctx = exec_ctx->device_ctx;
    marmot_tensor_t **concat_inputs = nullptr;
    const uint8_t *pc = imm;
    (void)const_pool;
    uint16_t weights_idx = marmot_bc_read_u16(&pc);
    uint16_t token_ids_idx = marmot_bc_read_u16(&pc);
    uint16_t out_idx = marmot_bc_read_u16(&pc);
    marmot_dtype_t dtype_out = (marmot_dtype_t)marmot_bc_read_u32(&pc);
    float scale = marmot_bc_read_f32(&pc);
    int32_t padding_id = (int32_t)marmot_bc_read_u32(&pc);
    bool bounds_check = marmot_bc_read_u8(&pc) != 0;
    bool prefer_gpu = marmot_bc_read_u8(&pc) != 0;
    bool allow_decode = marmot_bc_read_u8(&pc) != 0;
    marmot_kernel_args_embedding_t args = {
        .ctx = ctx,
        .weights = marmot_bc_reg(regs, weights_idx),
        .token_ids = marmot_bc_reg(regs, token_ids_idx),
        .out = marmot_bc_reg(regs, out_idx),
        .dtype_out = dtype_out,
        .scale = scale,
        .padding_id = padding_id,
        .bounds_check = bounds_check,
        .prefer_gpu_private = prefer_gpu,
        .allow_quant_decode_on_the_fly = allow_decode,
    };
    marmot_error_t status = marmot_cpu_embedding_float_exec(device_ctx, &args);
    if (concat_inputs != nullptr) {
        free(concat_inputs);
    }
    return status;
}

