#if MARMOT_ENABLE_ACCELERATE
static marmot_error_t marmot_cpu_bc_exec_rope_bf16_accelerate(
    const void *backend_exec_ctx, marmot_tensor_t **regs, const uint8_t *imm, const uint8_t *const_pool
) {
    const marmot_bc_exec_ctx_t *exec_ctx = (const marmot_bc_exec_ctx_t *)backend_exec_ctx;
    if (exec_ctx == nullptr || exec_ctx->ctx == nullptr || exec_ctx->device_ctx == nullptr || regs == nullptr ||
        imm == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Null bytecode exec arguments");
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    const marmot_context_t *ctx = exec_ctx->ctx;
    const void *device_ctx = exec_ctx->device_ctx;
    marmot_tensor_t **concat_inputs = nullptr;
    const uint8_t *pc = imm;
    uint16_t input_idx = marmot_bc_read_u16(&pc);
    uint16_t output_idx = marmot_bc_read_u16(&pc);
    uint16_t positions_idx = marmot_bc_read_u16(&pc);
    uint32_t params_offset = marmot_bc_read_u32(&pc);
    uint32_t n_past = marmot_bc_read_u32(&pc);
    uint32_t n_rot = marmot_bc_read_u32(&pc);
    const marmot_rope_params_t *params = (const marmot_rope_params_t *)marmot_bc_const_data(
        const_pool, params_offset, "Null const pool for rope params"
    );
    if (params_offset != MARMOT_BC_INVALID_OFFSET && params == nullptr) {
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    marmot_rope_params_t params_copy;
    const marmot_rope_params_t *params_ptr = params;
    if (positions_idx != MARMOT_BC_REG_INVALID) {
        if (params == nullptr) {
            marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Missing rope params");
            return MARMOT_ERROR_INVALID_ARGUMENT;
        }
        params_copy = *params;
        params_copy.positions = marmot_bc_reg(regs, positions_idx);
        params_ptr = &params_copy;
    }
    marmot_kernel_args_rope_t args = {
        .ctx = ctx,
        .input = marmot_bc_reg(regs, input_idx),
        .output = marmot_bc_reg(regs, output_idx),
        .rope_params = params_ptr,
        .n_past = n_past,
        .n_rot = n_rot,
    };
    marmot_error_t status = marmot_cpu_rope_bf16_accelerate_exec(device_ctx, &args);
    if (concat_inputs != nullptr) {
        free(concat_inputs);
    }
    return status;
}
#endif

