static marmot_error_t marmot_cpu_bc_exec_tensor_concat_generic(
    const void *backend_exec_ctx, marmot_tensor_t **regs, const uint8_t *imm, const uint8_t *const_pool
) {
    const marmot_bc_exec_ctx_t *exec_ctx = (const marmot_bc_exec_ctx_t *)backend_exec_ctx;
    if (exec_ctx == nullptr || exec_ctx->ctx == nullptr || exec_ctx->device_ctx == nullptr || regs == nullptr ||
        imm == nullptr) {
        marmot_set_error(MARMOT_ERROR_INVALID_ARGUMENT, "Null bytecode exec arguments");
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    const marmot_context_t *ctx = exec_ctx->ctx;
    const void *device_ctx = exec_ctx->device_ctx;
    marmot_tensor_t **concat_inputs = nullptr;
    const uint8_t *pc = imm;
    uint16_t output_idx = marmot_bc_read_u16(&pc);
    uint32_t inputs_offset = marmot_bc_read_u32(&pc);
    uint64_t num_inputs = marmot_bc_read_u64(&pc);
    int axis = (int)marmot_bc_read_u32(&pc);
    const uint16_t *input_regs =
        (const uint16_t *)marmot_bc_const_data(const_pool, inputs_offset, "Null const pool for concat inputs");
    if (inputs_offset != MARMOT_BC_INVALID_OFFSET && input_regs == nullptr) {
        return MARMOT_ERROR_INVALID_ARGUMENT;
    }
    size_t count = (size_t)num_inputs;
    marmot_tensor_t **inputs = nullptr;
    if (count > 0) {
        inputs = (marmot_tensor_t **)malloc(count * sizeof(*inputs));
        if (inputs == nullptr) {
            marmot_set_error(MARMOT_ERROR_OUT_OF_MEMORY, "Failed to allocate concat inputs");
            return MARMOT_ERROR_OUT_OF_MEMORY;
        }
        for (size_t i = 0; i < count; ++i) {
            inputs[i] = marmot_bc_reg(regs, input_regs[i]);
        }
    }
    concat_inputs = inputs;
    marmot_kernel_args_concat_t args = {
        .ctx = ctx,
        .inputs = (const marmot_tensor_t *const *)inputs,
        .num_inputs = count,
        .output = marmot_bc_reg(regs, output_idx),
        .axis = axis,
    };
    marmot_error_t status = marmot_cpu_tensor_concat_generic_exec(device_ctx, &args);
    if (concat_inputs != nullptr) {
        free(concat_inputs);
    }
    return status;
}

